// ── Extraer y validar payload ──────────────────────
const raw = $input.first().json;
const body = raw.body || raw;

const uuid    = String(body.uuid    || '').trim();
const message = String(body.message || '').trim();
const history = Array.isArray(body.history) ? body.history : [];

if (!uuid)    throw new Error('uuid es requerido');
if (!message) throw new Error('message es requerido');

// Limitar historial a últimos 20 mensajes para no exceder tokens
const trimmedHistory = history.slice(-20);

return [{ json: { uuid, message, history: trimmedHistory } }];

// ── Construir prompt para Claude ────────────────────
const extract = $('Extraer Input').first().json;
const redisResult = $input.first().json;

const { uuid, message, history } = extract;

// Parsear cotización guardada (si existe)
let quoteContext = '';
let existingQuote = null;

if (redisResult && redisResult.value) {
  try {
    existingQuote = JSON.parse(redisResult.value);
    quoteContext = `

=== COTIZACIÓN ACTIVA DEL CLIENTE ===
Número: ${existingQuote.numero}
Producto: ${existingQuote.tipo}
M²: ${existingQuote.m2} m²
Instalación: ${existingQuote.instalacion ? 'Sí' : 'No'}
Total: $${Number(existingQuote.total).toLocaleString('es-CL')} CLP
Fecha: ${existingQuote.fecha}

Si el cliente menciona su cotización o quiere pagar, usa estos datos.`;
  } catch(e) {
    existingQuote = null;
  }
}

// ── Sistema de precios (actualizar según negocio) ──
const systemPrompt = `Eres el asistente virtual de cotizaciones de Césped Sintético SpA, empresa de Melipilla, Chile.

TU MISIÓN:
1. Guiar al cliente para medir su espacio correctamente
2. Calcular los metros cuadrados necesarios
3. Ofrecer el producto más adecuado
4. Generar una cotización con número único
5. Crear un link de pago cuando el cliente esté listo

CATÁLOGO DE PRODUCTOS Y PRECIOS (CLP por m²):
- Pasto Deportivo (fibra 25mm): $12.000/m²  → canchas de fútbol, multideporte
- Pasto Ornamental Básico (fibra 20mm): $8.500/m²  → jardines, terrazas, balcones
- Pasto Ornamental Premium (fibra 35mm): $15.000/m²  → jardines de lujo
- Instalación (servicio adicional): $4.500/m²

CÓMO CALCULAR METRAJE:
- Rectangular: largo (m) × ancho (m) = m²
- Espacio irregular: dividir en rectángulos y sumar
- SIEMPRE agregar 10% de margen por cortes (redondear hacia arriba)
- Ejemplo: jardín 5×3m = 15 m² → con margen: 16.5 m² → pedir 17 m²

FLUJO OBLIGATORIO:
1. Saluda amablemente
2. Pregunta el tipo de espacio (jardín, cancha, terraza, etc.)
3. Pide las medidas: largo y ancho
4. Calcula m² con margen y explica el cálculo
5. Recomienda el producto según el uso
6. Pregunta si necesita instalación
7. Calcula el total (m² × precio + instalación si aplica)
8. Confirma los datos con el cliente
9. Genera la cotización

CUANDO TENGAS m², TIPO Y DECISIÓN DE INSTALACIÓN:
Incluye EXACTAMENTE esta línea al final de tu respuesta (sin cambiar formato):
[COTIZAR: m2=XX.XX, tipo=NOMBRE_PRODUCTO, instalacion=SI/NO, total=MONTO_SIN_PUNTOS]

Ejemplo: [COTIZAR: m2=17.00, tipo=Pasto Ornamental Básico, instalacion=SI, total=220500]

CUANDO EL CLIENTE CONFIRME QUE QUIERE PAGAR:
Incluye EXACTAMENTE esta línea al final de tu respuesta:
[PAGAR: numero=COT-XXXX-XXX, monto=MONTO_SIN_PUNTOS]

REGLAS IMPORTANTES:
- Habla en español chileno, amable y directo
- Nunca inventes precios fuera del catálogo
- Si el cliente ya tiene cotización activa, confirma sus datos antes de generar otra
- Sé conciso pero completo
- No incluyas los marcadores [COTIZAR:] o [PAGAR:] a menos que tengas TODOS los datos${quoteContext}`;

// Armar mensajes para Claude
const messages = [
  ...history,
  { role: 'user', content: message }
];

return [{ json: { uuid, systemPrompt, messages, existingQuote } }];

// ── Parsear respuesta de Claude ──────────────────────
const claudeResp = $input.first().json;
const prevData = $('Construir Prompt Claude').first().json;

const { uuid, existingQuote } = prevData;

// Extraer texto de la respuesta
let rawText = '';
if (claudeResp.content && claudeResp.content[0]) {
  rawText = claudeResp.content[0].text || '';
}

// Detectar marcadores especiales
const cotizarRegex = /\[COTIZAR:\s*m2=([\d.]+),\s*tipo=([^,]+),\s*instalacion=(SI|NO),\s*total=(\d+)\]/i;
const pagarRegex   = /\[PAGAR:\s*numero=([^,]+),\s*monto=(\d+)\]/i;

const cotizarMatch = rawText.match(cotizarRegex);
const pagarMatch   = rawText.match(pagarRegex);

// Limpiar texto (remover marcadores de la respuesta visible)
const cleanText = rawText
  .replace(cotizarRegex, '')
  .replace(pagarRegex, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

let action = 'NONE';
let actionData = null;

if (cotizarMatch) {
  action = 'COTIZAR';
  actionData = {
    m2: parseFloat(cotizarMatch[1]),
    tipo: cotizarMatch[2].trim(),
    instalacion: cotizarMatch[3].toUpperCase() === 'SI',
    total: parseInt(cotizarMatch[4], 10)
  };
} else if (pagarMatch) {
  action = 'PAGAR';
  actionData = {
    numero: pagarMatch[1].trim(),
    monto: parseInt(pagarMatch[2], 10)
  };
}

return [{ json: { uuid, cleanText, action, actionData, existingQuote } }];

// ── Crear objeto de cotización ───────────────────────
const parseData  = $('Parsear Respuesta Claude').first().json;
const counterVal = $input.first().json.value;

const { uuid, cleanText, actionData } = parseData;

// Formatear número de cotización: COT-2026-001
const year = new Date().getFullYear();
const seq  = String(counterVal || 1).padStart(3, '0');
const numero = `COT-${year}-${seq}`;

// Construir objeto de cotización
const quote = {
  numero,
  uuid,
  m2:         actionData.m2,
  tipo:       actionData.tipo,
  instalacion: actionData.instalacion,
  total:      actionData.total,
  fecha:      new Date().toLocaleDateString('es-CL', { day: '2-digit', month: '2-digit', year: 'numeric' }),
  timestamp:  Date.now()
};

// Generar mensaje amigable con resumen
const msgInstalacion = quote.instalacion
  ? `\n🔧 Instalación incluida`
  : '';

const msgFinal = cleanText +
  `\n\n✅ ¡Cotización generada! Te la guardo por 10 días.\n\n` +
  `📋 Número: **${quote.numero}**\n` +
  `📐 Metros cuadrados: ${quote.m2} m²\n` +
  `🌿 Producto: ${quote.tipo}` +
  msgInstalacion +
  `\n💰 Total: $${quote.total.toLocaleString('es-CL')} CLP\n\n` +
  `¿Deseas proceder con el pago? Solo dime y te genero el link de MercadoPago.`;

return [{ json: { uuid, quote, message: msgFinal } }];

// ── Respuesta al frontend con cotización ─────────────
const quoteData = $('Crear Cotización').first().json;

return [{
  json: {
    message: quoteData.message,
    quote:   quoteData.quote,
    paymentLink: null
  }
}];

// ── Respuesta al frontend con link de pago ───────────
const mpResp = $input.first().json;
const parseData = $('Parsear Respuesta Claude').first().json;

const paymentLink = mpResp.init_point || mpResp.sandbox_init_point || null;

const message = parseData.cleanText +
  (paymentLink
    ? `\n\n💳 ¡Listo! Aquí está tu link de pago para la cotización **${parseData.actionData.numero}**:\n\nHaz clic en el botón de abajo para pagar de forma segura con MercadoPago.`
    : `\n\nHubo un problema al generar el link de pago. Por favor contáctanos directamente.`);

return [{
  json: {
    message,
    quote: parseData.existingQuote || null,
    paymentLink
  }
}];

// ── Respuesta simple (sin acción especial) ───────────
const parseData = $input.first().json;

return [{
  json: {
    message: parseData.cleanText,
    quote: parseData.existingQuote || null,
    paymentLink: null
  }
}];
